import dayjs from 'dayjs'
import duration from 'dayjs/plugin/duration'
import React from 'react'
import useElapsedTime from '../hook/useElapsedTime'
import type { GameRunningStatus } from '../types'

dayjs.extend(duration)

export interface IElapsedTimerProps {
  /**
   * Game status.
   */
  gameStatus: GameRunningStatus
  /**
   * How many milliseconds to refresh.
   * @default 1000
   */
  delay?: number
  /**
   * Initial used time.
   */
  initialUsedTime?: number
  /**
   * Initial game status.
   */
  initialStatus?: GameRunningStatus.PENDING | GameRunningStatus.PAUSED
  /**
   * Dayjs time format.
   * @default 'HH:mm:ss'
   */
  format?: string
  className?: string
  style?: React.CSSProperties
  onUsedTimeChange?(usedTime: number): void
}

/**
 *
 * @param props
 * @returns
 */
export function ElapsedTimer(props: IElapsedTimerProps): React.ReactElement {
  const {
    gameStatus,
    delay = 1000,
    format = 'HH:mm:ss',
    className,
    style,
    initialUsedTime,
    initialStatus,
    onUsedTimeChange,
  } = props
  const usedTime: number = useElapsedTime(gameStatus, initialUsedTime, initialStatus)
  const usedTimeString: string = dayjs.duration(usedTime).format(format)

  const [, setTick] = React.useState<number>(0)

  React.useEffect(() => {
    if (gameStatus !== 'running') return

    const remain: number = delay - (usedTime % delay)
    const refresh = (): void => setTick(v => v + 1)

    let timeout1: any
    let timeout2: any

    const refresh2 = (): void => {
      timeout1 = undefined
      refresh()
      timeout2 = setInterval(refresh, delay)
    }

    timeout1 = setTimeout(refresh2, remain)
    return (): void => {
      if (timeout1) clearTimeout(timeout1)
      if (timeout2) clearInterval(timeout2)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [gameStatus, delay])

  React.useEffect(() => {
    onUsedTimeChange?.(usedTime)
  }, [usedTime, onUsedTimeChange])

  return (
    <span className={className} style={style}>
      {usedTimeString}
    </span>
  )
}

ElapsedTimer.displayName = 'ElapsedTimer'
export default ElapsedTimer
